mapper.select:
select 
from file_parse_record
where project_id = #{projectId}
  and file_id = #{fileId}
  and deleted = 0
order by created_at desc, id desc

select 
from file_parse_record
where project_id = #{projectId}
  and file_id = #{fileId}
  and source_file_hash = #{sourceFileHash}
  and result_format = #{resultFormat}
  and status = 'SUCCESS'
  and result_object_name is not null
  and deleted = 0
order by finished_at desc, id desc
limit 1
